import Mathlib
 import Mathlib.Tactic.Classic
import Mathlib.Tactic.Expr
import Mathlib.Tactic.Int.Basic

open Lean
open Nat
open Function

Definition init (p : Nat → Nat) : Nat := p 0

Definition main : Nat → Nat := fun n => do {
  let mut n' := n
  let mut p := 0
  let mut q := 1
  let mut r := n'
  let mut h := 0

  while q ≤ n' do
    have q_is_power_of_four := by {
      have four_q := by {
        simp [Nat.pow]
        ring
        rw [Nat.pow_two, Nat.pow_mul, Nat.pow_one]
      }
      rw [this, four_q]
    }

    have p_is_half_of_q := by {
      have h_is_half_of_q := by {
        rw [Nat.div_eq_mul_inv] at q_is_power_of_four
        rw [Nat.div_eq_mul_inv] at this
        rw [Nat.pow_two]
        ring
      }
      rw [Nat.div_eq_mul_inv] at h_is_half_of_q
      rw [this]
    }

    have p_is_less_than_r_plus_q := by {
      rw [Nat.lt_add_left] at p_is_half_of_q
      rw [p_is_half_of_q]
      rw [Nat.lt_trans] at p_is_half_of_q
      rw [Nat.lt_refl r] at this
    }

    have new_h := p + q
    have new_p := p / 2

    have new_p_is_less_than_new_h := by {
      rw [Nat.lt_add_left] at new_p_is_half_of_q
      rw [new_p_is_half_of_q]
      rw [Nat.lt_trans] at new_p_is_half_of_q
      rw [Nat.lt_refl new_h]
    }

    have h_is_greater_than_r := by {
      have q_is_greater_than_r := by {
        rw [Nat.lt_add_right q r]
        simp [Nat.succ_le_self]
      }
      rw [Nat.lt_trans] at q_is_greater_than_r
      rw [q_is_power_of_four]
      rw [Nat.pow_succ]
    }

    have r_is_greater_than_h := by {
      have h_is_less_than_r := by {
        rw [Nat.lt_trans] at h_is_less_than_q
        rw [h_is_less_than_q]
      }
      rw [Nat.lt_trans] at h_is_less_than_r
      rw [h_is_greater_than_r]
    }

    if h_is_greater_than_r then do {
      have new_p_is_greater_than_new_r := by {
        rw [Nat.add_lt_add_left] at new_p_is_less_than_new_h
        rw [new_p_is_less_than_new_h]
      }

      set p := p + q
      set r := r - h
    }

    set q := q * 4
    set h := new_h
    set p := new_p
  }

  let h_squared_minus_twelve_h_times_n := h * h - 12 * h * n
  let sixteen_n_p_times_q := 16 * n * p * q
  let sixteen_p_q_times_r := 16 * p * q * r
  let h_times_h_times_p_minus_four_h_times_n_times_q := h * h * p - 4 * h * n * q
  let p_squared_minus_n_times_q_plus_q_times_r := p * p - n * q + q * r

  have h_squared_minus_twelve_h_times_n_is_zero := by assumption
  have sixteen_n_p_times_q_is_equal_to_n_times_q_times_r := by assumption
  have sixteen_p_q_times_r_is_equal_to_h_times_h_times_p_minus_four_h_times_n_times_q_minus_h_times_q_times_q_plus_four_p_times_q_times_r := by {
    ring
    have h_times_q_times_q_minus_four_p_times_q_times_r := h * q * q - 4 * p * q * r

    rw [Nat.sub_eq_add] at this
    have h_times_q_times_q_is_equal_to_p_squared_minus_n_times_q_plus_q_times_r := by {
      ring
      rw [h_times_h_times_p_minus_four_h_times_n_times_q]
      rw [h_times_q_times_q]
      rw [Nat.sub_eq_add] at this
      have h_times_q_times_q_is_equal_to_p_squared := by rw [h_times_q_times_q_minus_four_p_times_q_times_r, Nat.add_sub_cancel _ _]
      rw [h_times_q_times_q_is_equal_to_p_squared]
    }

    rw [this, sixteen_n_p_times_q]
  }

  have h_times_h_times_h_minus_twelve_h_times_n_plus_sixteen_n_p_times_q_minus_four_h_times_p_times_r_is_zero := by {
    ring
    have h_times_h_times_h_minus_twelve_h_times_n := h * h * h - 12 * h * n

    rw [Nat.sub_eq_add] at this
    rw [h_squared_minus_twelve_h_times_n_is_zero] at this

    rw [h_times_h_times_h_minus_twelve_h_times_n_plus_sixteen_n_p_times_q_minus_four_h_times_p_times_r, sixteen_p_q_times_r_is_equal_to_h_times_h_times_p_minus_four_h_times_n_times_q_minus_h_times_q_times_q_plus_four_p_times_q_times_r]
  }

  have p_squared_minus_n_plus_q_times_r_is_zero := by assumption

  have h_times_h_times_p_minus_four_h_times_n_times_q_is_zero := by assumption
}

